questionvariables.text:
/* 1. Randomize Centre O */
cx: -2 + rand(5); 
cy: -2 + rand(5); 
ta1: [cx, cy];

/* 2. Randomize Angle */
angle_list: [90, -90, 180, 270];
ta2: random_permutation(angle_list)[1];

/* 3. Define the 'Bench' (Line Segment AB) */
/* Coordinates are relative to centre to ensure they stay on the grid */
ax_orig: cx + 2 + rand(2);
ay_orig: cy + 1 + rand(2);
bx_orig: ax_orig - 1;
by_orig: ay_orig - 2;

pA: [ax_orig, ay_orig];
pB: [bx_orig, by_orig];

/* 4. Rotation Logic - CRITICAL: Pre-calculate as pure numbers */
rad: (ta2 * %pi) / 180;

/* Calculate A' */
ax_p: round(float(cx + (pA[1]-cx)*cos(rad) - (pA[2]-cy)*sin(rad)));
ay_p: round(float(cy + (pA[1]-cx)*sin(rad) + (pA[2]-cy)*cos(rad)));
pA_prime: [ax_p, ay_p];

/* Calculate B' */
bx_p: round(float(cx + (pB[1]-cx)*cos(rad) - (pB[2]-cy)*sin(rad)));
by_p: round(float(cy + (pB[1]-cx)*sin(rad) + (pB[2]-cy)*cos(rad)));
pB_prime: [bx_p, by_p];
